"use strict";parserFactory.register("goldennovel.com",()=>new GoldennovelParser);class GoldennovelParser extends Parser{async getChapterUrls(e){let r=e.querySelector("div#content-b ul.list.clearfix");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector("div.content")}findChapterTitle(e){return e.querySelector("h1.align-center")}extractAuthor(e){let r=e.querySelector("span.tip");if(r&&r.textContent.includes("Author:")){let e=r.parentElement.querySelector("a");if(e)return e.textContent}return super.extractAuthor(e)}findCoverImageUrl(e){let r=e.querySelector("div.cover img");return r?r.src:null}}